// Enhanced fetch wrapper for network logging
const originalFetch = global.fetch;

global.fetch = function(...args) {
  const startTime = Date.now();
  const url = args[0];
  const options = args[1];
  
  DebugLogger.logUserAction('fetch_request', {
    url,
    method: options?.method || 'GET',
    headers: options?.headers
  });
  
  return originalFetch.apply(this, args)
    .then(response => {
      const duration = Date.now() - startTime;
      DebugLogger.logNetworkRequest(
        url,
        options?.method || 'GET',
        options?.body,
        response,
        duration
      );
      return response;
    })
    .catch(error => {
      const duration = Date.now() - startTime;
      DebugLogger.logNetworkRequest(
        url,
        options?.method || 'GET',
        options?.body,
        null,
        duration,
        error
      );
      throw error;
    });
};

// Enhanced AsyncStorage wrapper
const originalAsyncStorage = AsyncStorage;

AsyncStorage.getItem = function(key) {
  return originalAsyncStorage.getItem(key)
    .then(value => {
      DebugLogger.logAsyncStorage('get', key, value);
      return value;
    })
    .catch(error => {
      DebugLogger.logAsyncStorage('get', key, null, error.message);
      throw error;
    });
};

AsyncStorage.setItem = function(key, value) {
  return originalAsyncStorage.setItem(key, value)
    .then(() => {
      DebugLogger.logAsyncStorage('set', key, value);
      return value;
    })
    .catch(error => {
      DebugLogger.logAsyncStorage('set', key, value, error.message);
      throw error;
    });
};

AsyncStorage.removeItem = function(key) {
  return originalAsyncStorage.removeItem(key)
    .then(() => {
      DebugLogger.logAsyncStorage('remove', key, null);
      return key;
    })
    .catch(error => {
      DebugLogger.logAsyncStorage('remove', key, null, error.message);
      throw error;
    });
};

export default DebugLogger;